import serial
import datetime

# IMPORTANT: Change this to the SECOND port generated by socat
TARGET_PORT = '/dev/ttys006' 

def decode_packet(packet_bytes):
    """Applies your decoding logic to an 8-byte hex array."""
    if len(packet_bytes) != 8:
        return

    # Decoding Logic based on your provided script
    # Byte 1: Ambiance Temp (Scaling: / 2)
    amb_temp = packet_bytes[1] / 2.0
    
    # Byte 2: Stack Temp (Scaling: / 3)
    stack_temp = packet_bytes[2] / 3.0
    
    # Byte 4: Stack Current (Scaling: / 2)
    stack_current = packet_bytes[4] / 2.0
    
    # Byte 7: Battery Voltage (Scaling: / 10)
    bat_voltage = packet_bytes[7] / 10.0
    
    # Static/Derived values 
    status = "'NORMAL'"
    stack_voltage = 0.200000 
    stack_power = 9.200000   
    
    # Generate a live timestamp for when the packet was received
    now = datetime.datetime.now()
    formatted_time = now.strftime("'%m/%d/%Y %I:%M:%S %p'")
    
    # Print formatted output
    print(f"{formatted_time:<25} {status:<10} {int(amb_temp):<12} {stack_temp:<15.6f} {stack_voltage:<12.6f} {int(stack_current):<12} {stack_power:<12.6f} {bat_voltage:<10.6f}")


def read_from_port():
    print(f"Listening on {TARGET_PORT}...")
    
    # Print the header exactly like your decoder
    print(f"{'Date & Time':<25} {'Status':<10} {'Amb Temp(C)':<12} {'Stack Temp(C)':<15} {'Stack V(V)':<12} {'Stack I(A)':<12} {'Stack P(W)':<12} {'Bat V(V)':<10}")
    print("-" * 120)

    # Buffer to hold incoming bytes until we have a full 8-byte packet
    buffer = bytearray()

    try:
        with serial.Serial(TARGET_PORT, 9600, timeout=1) as ser:
            while True:
                if ser.in_waiting > 0:
                    # Read whatever is currently available
                    chunk = ser.read(ser.in_waiting)
                    buffer.extend(chunk)

                    # Process packets as long as we have at least 8 bytes in the buffer
                    while len(buffer) >= 8:
                        packet = buffer[:8]      # Grab the first 8 bytes
                        buffer = buffer[8:]      # Remove them from the buffer
                        
                        decode_packet(packet)    # Send to your decoder

    except KeyboardInterrupt:
        print("\nExiting...")
    except Exception as e:
        print(f"Error: {e}")

if __name__ == '__main__':
    read_from_port()

